def delete_and_earn(nums):
    if not nums:
        return 0
    U = max(nums)
    gain = [0] * (U + 1)
    for x in nums:
        gain[x] += x
    prev2, prev1 = 0, 0
    for v in range(U + 1):
        prev2, prev1 = prev1, max(prev1, prev2 + gain[v])
    return prev1

